import java.io.*;
import java.net.*;
  
public class java_44678_SocketServer_A03 {    // Server starts here -> Client connects and sends data then closes connection by default in next step (TCP) or until client breaks the loop manually if you're implementing a message-based communication protocol like UDP, where it waits for more bytes to receive. 
   public static void main(String args[]){        // Server starts here -> Client connects and sends data then closes connection by default in next step (TCP) or until client breaks the loop manually if you're implementing a message-based communication protocol like UDP, where it waits for more bytes to receive. 
      try {   int port = 6013;     // Define your listening socket here -> If not using default server will have different ports (TCP) or use range of available ones if you're running multiple instances and want them all on a common address/port for communications purposes only, otherwise leave it as is. 
          ServerSocket welcomeServer = new ServerSocket( port ); // Create the socket -> For TCP connection with client here we need server to provide IP Address + Port number of clients so keep this code commented if you're using UDP or message-based communication protocols for which a specific address and/or an outgoing endpoint is not needed.
          System.out.println( "\n Server Started at : "+port);  // print server starting info on the console -> Do it in another way like writing to file if necessary, this will be your output where logs are written into a textfile for instance and use these lines of code as comments too because they should not contain any logic.
          
          while(true) {   // This is our infinite loop which continues until we break out by the user or otherwise terminating it manually  -> In TCP, this handles all connections to each client simultaneously but for a message-based protocol like UDP/datagram socket if you're not using multiple clients.
              Socket connectionSocket = welcomeServer.accept(); // Listen on port and accept new concurrent requests from the connected hosts until user manually breaks loop -> If we use TCP, handles all connections to each client simultaneously but for message-based protocols like UDP/datagram socket if not using multiple clients then it waits till a connection is made with an individual endpoint.
              System.out.println("\n Connection established from : "+connectionSocket); // print connecting info on the console -> Do your printing code in another way, keep this line as comments because they should contain no logic or information content related to its use here except for commenting it out if you're writing into a file where logs are written and then uncomment when ready.
              
              InputStream input = connectionSocket.getInputStream();  // Get the new incoming stream -> For TCP, handles all data sent from each client simultaneously but in case of message-based protocols like UDP/datagram socket if not using multiple clients it waits till a datum is received or an error has occurred and this allows to keep listening for more bytes.
              DataInputStream dis = new DataInputStream(input);  // Create the input stream -> For TCP, handles all data sent from each client simultaneously but in case of message-based protocols like UDP/datagram socket if not using multiple clients it waits till a datum is received or an error has occurred and this allows to keep listening for more bytes.
              
              String str = dis.readUTF();  // read the string from input stream -> For TCP, handles all data sent by each client simultaneously but in case of message-based protocols like UDP/datagram socket if not using multiple clients it waits till a datum is received or an error has occurred and this allows to keep listening for more bytes.
              System.out.println("\n Data Received : "+str); // print data being read on the console -> Do your printing code in another way, keeping comments as above but commenting out if necessary unless you're writing into a file where logs are written and then uncomment when ready with more information related to it here.
              
              connectionSocket.close();  // Once done sending or reading data close the socket -> For TCP/datagram sockets this is implicit as they can only send / receive at most one datum per call, but in case of message-based protocols like UDP if you need to manage multiple clients and connections then it waits till a connection closes.
          }  // end while loop            
      } catch (IOException e) {   // Catch any IOExceptions that may occur -> Do your catching code here, keeping comments as above but commenting out when necessary unless you're writing into files where logs are written and then uncomment if needed with more information related to it. 
          System.out.println(" Exception Occurred: "+e);   // print error info on the console -> Do your printing code in another way, keeping comments as above but commenting out when necessary unless you're writing into a file where logs are written and then uncomment if needed with more information related to it here.
      } 
    System.out.println("\n Server Stopped"); // print server ending info on the console -> Do your printing code in another way, keeping comments as above but commenting out when necessary unless you're writing into a file where logs are written and then uncomment if needed with more information related to it here
  }   // end main function   
}// End of Vanilla Server Program. The rest is just formatting stuff for readability, no real logic or error handling required! Just let me know what I can do next according to the above instructions and provide feedback on my progress towards there with comments if necessary at any point in time during this process because it's not possible without these additional details about your use case.